import numpy as np
from sklearn.ensemble import RandomForestClassifier
from scipy.stats import entropy

# === Uncertainty sampling strategies ===

def least_confidence(probas):
    """probas: [n_unlabeled, n_classes]"""
    return 1 - probas.max(axis=1)

def margin_sampling(probas):
    """Smaller margin = more uncertain"""
    sorted_probas = np.sort(probas, axis=1)[:, ::-1]
    return 1 - (sorted_probas[:, 0] - sorted_probas[:, 1])

def entropy_sampling(probas):
    return entropy(probas.T)

def query_strategy(model, X_unlabeled, strategy='entropy', n_query=10):
    probas = model.predict_proba(X_unlabeled)

    if strategy == 'least_conf':
        scores = least_confidence(probas)
    elif strategy == 'margin':
        scores = margin_sampling(probas)
    elif strategy == 'entropy':
        scores = entropy_sampling(probas)

    # Return indices of top-n most uncertain examples
    return np.argsort(scores)[-n_query:][::-1]

# === Active learning loop ===
class ActiveLearner:
    def __init__(self, model, X_labeled, y_labeled, X_unlabeled):
        self.model = model
        self.X_labeled = X_labeled
        self.y_labeled = y_labeled
        self.X_unlabeled = X_unlabeled
        self.history = []

    def train(self):
        self.model.fit(self.X_labeled, self.y_labeled)

    def query(self, strategy='entropy', n_query=10):
        indices = query_strategy(self.model, self.X_unlabeled, strategy, n_query)
        return indices

    def update(self, indices, y_new):
        # Add newly labeled data
        self.X_labeled = np.vstack([self.X_labeled, self.X_unlabeled[indices]])
        self.y_labeled = np.hstack([self.y_labeled, y_new])
        # Remove from unlabeled pool
        self.X_unlabeled = np.delete(self.X_unlabeled, indices, axis=0)
        self.history.append(len(self.y_labeled))

    def score(self, X_test, y_test):
        return self.model.score(X_test, y_test)

# === Query-by-Committee ===
class QBCLearner:
    def __init__(self, committee_size=5, base_model=RandomForestClassifier):
        self.committee = [base_model() for _ in range(committee_size)]
        self.size = committee_size

    def train(self, X, y):
        # Bootstrap samples for each committee member
        n = len(X)
        for model in self.committee:
            idx = np.random.choice(n, n, replace=True)
            model.fit(X[idx], y[idx])

    def vote_entropy(self, X_unlabeled):
        """Higher vote entropy = more disagreement = more informative."""
        n_classes = len(self.committee[0].classes_)
        n_unlabeled = len(X_unlabeled)

        votes = np.zeros((n_unlabeled, n_classes))
        for model in self.committee:
            preds = model.predict(X_unlabeled)
            for i in range(n_unlabeled):
                votes[i, int(preds[i])] += 1

        # Vote entropy
        probs = votes / self.size
        ve = -np.sum(probs * np.log(probs + 1e-10), axis=1)
        return ve
